  Int: 'number',
  Float: 'number',
  Boolean: 'boolean',
  Long: 'number',
  DateTime: ['Date', 'string'],    // Union type for compatibility
  ID: 'string',
  UUID: 'string',
  Json: 'runtime.JsonValue',
