**Iterating Fields Within a Model:**

From `Input.ts`:

```typescript
function buildInputField(field: DMMF.SchemaArg, context: GenerateContext): ts.Property {
  const tsType = buildAllFieldTypes(field.inputTypes, context)

  const tsProperty = ts.property(field.name, field.isRequired ? tsType : unionWithSkip)
  if (!field.isRequired) {
    tsProperty.optional()
  }

  if (field.comment) {
    tsProperty.setDocComment(ts.docComment(field.comment))
  }

  return tsProperty
