const userInterface = ts.interfaceDeclaration('User')
  .add(ts.property('id', ts.stringType))
  .add(ts.property('name', ts.stringType))
  .add(ts.property('age', ts.unionType([ts.numberType, ts.nullType]))
    .optional())

const file = ts.file()
  .addImport(ts.namedImport(['Prisma'], '@prisma/client'))
  .add(ts.moduleExport(userInterface))

const code = ts.stringify(file)
```

