### **7. End-to-End Example: Building a Model Interface**

Here's how to generate a TypeScript interface from a Prisma model:

```typescript
import * as ts from '@prisma/ts-builders'
import type * as DMMF from '@prisma/dmmf'

function generateModelInterface(model: DMMF.Model, typeMap: Record<string, string>) {
  const properties: ts.Property[] = model.fields.map(field => {
    // Map Prisma type to TypeScript type
    let tsType: ts.TypeBuilder

    if (field.kind === 'object') {
      tsType = ts.namedType(`Prisma.${field.type}Payload`)
    } else if (field.kind === 'enum') {
      tsType = ts.namedType(`$Enums.${field.type}`)
    } else {
      const typeName = typeMap[field.type] ?? field.type
      tsType = ts.namedType(typeName)
    }

    // Handle list and nullability
    if (field.isList) {
      tsType = ts.array(tsType)
    } else if (!field.isRequired) {
      tsType = ts.unionType([tsType, ts.nullType])
    }

    // Create property
    const prop = ts.property(field.name, tsType)
    if (!field.isRequired && !field.isList) {
      prop.optional()
    }
    if (field.documentation) {
      prop.setDocComment(ts.docComment(field.documentation))
    }
    return prop
  })

  // Build interface
  const iface = ts.interfaceDeclaration(`${model.name}Model`)
    .addMultiple(properties)

  // Export in a file
  const file = ts.file()
    .add(ts.moduleExport(iface))

  return ts.stringify(file)
}
```

