import type { Field, Model } from '@prisma/dmmf'

import { scalarToTypescript } from './scalar-to-typescript'

/** Generates a TypeScript interface for a single DMMF model. */
export function generateModelInterface(model: Model): string {
  const fields = model.fields
    .filter((f) => f.kind !== 'object')
    .map((f) => formatField(f))

  const lines = [`export interface ${model.name} {`, ...fields.map((f) => `  ${f}`), '}']

  return lines.join('\n')
}

function formatField(field: Field): string {
  let tsType = scalarToTypescript(field.type)

  if (field.isList) {
    tsType = `${tsType}[]`
  }

  const optional = !field.isRequired && !field.isList ? '?' : ''
  const nullable = !field.isRequired && !field.isList ? ' | null' : ''

  return `${field.name}${optional}: ${tsType}${nullable}`
}

/**
 * Generates auxiliary input types used by create and update operations.
 *
 * - `CreateInput` omits fields with defaults, auto-increment ids, and
 *   `updatedAt` fields, making them optional.
 * - `UpdateInput` makes every field optional via `Partial`.
 */
export function generateInputTypes(model: Model): string {
  const scalarFields = model.fields.filter((f) => f.kind !== 'object')

  const requiredForCreate = scalarFields.filter((f) => !hasAutoDefault(f) && f.isRequired)
  const optionalForCreate = scalarFields.filter((f) => hasAutoDefault(f) || !f.isRequired)

  const createLines = [
    `export interface ${model.name}CreateInput {`,
    ...requiredForCreate.map((f) => `  ${formatField(f)}`),
    ...optionalForCreate.map((f) => {
      const tsType = field.isList ? `${scalarToTypescript(f.type)}[]` : scalarToTypescript(f.type)
      return `  ${f.name}?: ${tsType}${!f.isRequired && !f.isList ? ' | null' : ''}`
    }),
    '}',
  ]

  const updateLines = [`export type ${model.name}UpdateInput = Partial<${model.name}CreateInput>`]

  return [createLines.join('\n'), '', updateLines.join('\n')].join('\n')
}

function hasAutoDefault(field: Field): boolean {
  if (!field.hasDefaultValue) return false
  if (field.isUpdatedAt) return true

  const def = field.default
  if (def != null && typeof def === 'object' && 'name' in def) {
    const name = (def as { name: string }).name
    return name === 'autoincrement' || name === 'uuid' || name === 'cuid' || name === 'now' || name === 'auto'
  }

  return false
}

