import type { Model } from '@prisma/dmmf'

import { scalarToTypescript } from './scalar-to-typescript'

/**
 * Generates a `WhereUniqueInput` type for a model, containing the fields
 * that can uniquely identify a record (primary key or `@unique` fields).
 */
export function generateWhereUniqueInput(model: Model): string {
  const uniqueFields = model.fields.filter((f) => f.kind !== 'object' && (f.isId || f.isUnique))

  if (uniqueFields.length === 0) {
    return `export type ${model.name}WhereUniqueInput = Record<string, unknown>`
  }

  const fields = uniqueFields.map((f) => {
    const tsType = scalarToTypescript(f.type)
    return `  ${f.name}?: ${tsType}`
  })

  return [`export interface ${model.name}WhereUniqueInput {`, ...fields, '}'].join('\n')
}

