import type * as DMMF from '@prisma/dmmf'

import { generateCrudMethods } from './generate-crud-methods'
import { generateEnum } from './generate-enum'
import { generateInputTypes, generateModelInterface } from './generate-model-interface'
import { generateWhereUniqueInput } from './generate-where-input'

/**
 * Orchestrates generation of the full REST API client source from a DMMF
 * document. Returns a single TypeScript source string ready to be written
 * to disk.
 */
export function generateRestClient(dmmf: DMMF.Document): string {
  const sections: string[] = [header()]

  for (const enumDef of dmmf.datamodel.enums) {
    sections.push(generateEnum(enumDef))
  }

  for (const model of dmmf.datamodel.models) {
    sections.push(generateModelInterface(model))
    sections.push(generateInputTypes(model))
    sections.push(generateWhereUniqueInput(model))
    sections.push(generateCrudMethods(model))
  }

  sections.push(generateTopLevelClient(dmmf.datamodel.models))

  return sections.join('\n\n') + '\n'
}

function header(): string {
  return [
    '// -----------------------------------------------',
    '// Generated by @prisma/generator-rest-api',
    '// Do not edit manually.',
    '// -----------------------------------------------',
  ].join('\n')
}

/**
 * Generates the top-level `RestApiClient` interface that aggregates the
 * per-model CRUD client interfaces under camelCase property names.
 */
function generateTopLevelClient(models: readonly DMMF.Model[]): string {
  if (models.length === 0) {
    return 'export interface RestApiClient {}'
  }

  const entries = models.map((m) => `  ${camelCase(m.name)}: ${m.name}Client`)

  return ['export interface RestApiClient {', ...entries, '}'].join('\n')
}

function camelCase(name: string): string {
  return name.charAt(0).toLowerCase() + name.slice(1)
}

