import fs from 'node:fs'
import path from 'node:path'

import type { GeneratorConfig, GeneratorManifest, GeneratorOptions } from '@prisma/generator'

import { generateRestClient } from './generate-rest-client'

const DEFAULT_OUTPUT = 'rest-api-client'

export class RestApiGenerator {
  readonly name = 'prisma-generator-rest-api'

  async getManifest(_config: GeneratorConfig): Promise<GeneratorManifest> {
    return {
      defaultOutput: DEFAULT_OUTPUT,
      prettyName: 'Prisma REST API Client',
    }
  }

  async generate(options: GeneratorOptions): Promise<void> {
    const output = options.generator.output?.value
    if (!output) {
      throw new Error('@prisma/generator-rest-api: No output directory configured')
    }

    const source = generateRestClient(options.dmmf)
    const outputDir = path.resolve(output)

    await fs.promises.mkdir(outputDir, { recursive: true })
    await fs.promises.writeFile(path.join(outputDir, 'index.ts'), source, 'utf-8')
  }
}

