import type * as DMMF from '@prisma/dmmf'
import { describe, expect, test } from 'vitest'

import { generateRestClient } from '../generate-rest-client'

function makeDmmf(models: DMMF.Model[], enums: DMMF.DatamodelEnum[] = []): DMMF.Document {
  return {
    datamodel: {
      models,
      enums,
      types: [],
      indexes: [],
    },
    schema: {
      inputObjectTypes: { prisma: [], model: undefined },
      outputObjectTypes: { prisma: [], model: undefined },
      enumTypes: { prisma: [], model: undefined },
      fieldRefTypes: { prisma: [], model: undefined },
      hasJsonTypes: false,
    },
    mappings: {
      modelOperations: [],
      otherOperations: { read: [], write: [] },
    },
  }
}

function makeModel(name: string, fields: DMMF.Field[]): DMMF.Model {
  return {
    name,
    dbName: null,
    schema: null,
    fields,
    uniqueFields: [],
    uniqueIndexes: [],
    primaryKey: null,
  }
}

function makeField(overrides: Partial<DMMF.Field> & { name: string; type: string }): DMMF.Field {
  return {
    kind: 'scalar',
    name: overrides.name,
    isRequired: true,
    isList: false,
    isUnique: false,
    isId: false,
    isReadOnly: false,
    type: overrides.type,
    hasDefaultValue: false,
    ...overrides,
  }
}

describe('generateRestClient', () => {
  test('generates header comment', () => {
    const result = generateRestClient(makeDmmf([]))
    expect(result).toContain('Generated by @prisma/generator-rest-api')
    expect(result).toContain('Do not edit manually')
  })

  test('generates interface for a simple model', () => {
    const model = makeModel('User', [
      makeField({ name: 'id', type: 'Int', isId: true, hasDefaultValue: true, default: { name: 'autoincrement', args: [] } }),
      makeField({ name: 'email', type: 'String', isUnique: true }),
      makeField({ name: 'name', type: 'String', isRequired: false }),
    ])

    const result = generateRestClient(makeDmmf([model]))

    expect(result).toContain('export interface User {')
    expect(result).toContain('id: number')
    expect(result).toContain('email: string')
    expect(result).toContain('name?: string | null')
  })

  test('generates CreateInput with auto-default fields optional', () => {
    const model = makeModel('User', [
      makeField({ name: 'id', type: 'Int', isId: true, hasDefaultValue: true, default: { name: 'autoincrement', args: [] } }),
      makeField({ name: 'email', type: 'String' }),
    ])

    const result = generateRestClient(makeDmmf([model]))

    expect(result).toContain('export interface UserCreateInput {')
    expect(result).toContain('id?: number')
    expect(result).toContain('email: string')
  })

  test('generates UpdateInput as Partial of CreateInput', () => {
    const model = makeModel('Post', [
      makeField({ name: 'id', type: 'Int', isId: true }),
      makeField({ name: 'title', type: 'String' }),
    ])

    const result = generateRestClient(makeDmmf([model]))

    expect(result).toContain('export type PostUpdateInput = Partial<PostCreateInput>')
  })

  test('generates WhereUniqueInput with id and unique fields', () => {
    const model = makeModel('User', [
      makeField({ name: 'id', type: 'Int', isId: true }),
      makeField({ name: 'email', type: 'String', isUnique: true }),
      makeField({ name: 'name', type: 'String' }),
    ])

    const result = generateRestClient(makeDmmf([model]))

    expect(result).toContain('export interface UserWhereUniqueInput {')
    expect(result).toContain('id?: number')
    expect(result).toContain('email?: string')
    expect(result).not.toMatch(/UserWhereUniqueInput[\s\S]*?name\?/)
  })

  test('generates CRUD method interface', () => {
    const model = makeModel('Post', [
      makeField({ name: 'id', type: 'Int', isId: true }),
      makeField({ name: 'title', type: 'String' }),
    ])

    const result = generateRestClient(makeDmmf([model]))

    expect(result).toContain('export interface PostClient {')
    expect(result).toContain('findMany(): Promise<Post[]>')
    expect(result).toContain('findUnique(where: PostWhereUniqueInput): Promise<Post | null>')
    expect(result).toContain('create(data: PostCreateInput): Promise<Post>')
    expect(result).toContain('update(where: PostWhereUniqueInput, data: PostUpdateInput): Promise<Post>')
    expect(result).toContain('delete(where: PostWhereUniqueInput): Promise<Post>')
  })

  test('generates top-level RestApiClient aggregating all models', () => {
    const userModel = makeModel('User', [
      makeField({ name: 'id', type: 'Int', isId: true }),
    ])
    const postModel = makeModel('Post', [
      makeField({ name: 'id', type: 'Int', isId: true }),
    ])

    const result = generateRestClient(makeDmmf([userModel, postModel]))

    expect(result).toContain('export interface RestApiClient {')
    expect(result).toContain('user: UserClient')
    expect(result).toContain('post: PostClient')
  })

  test('handles enum types', () => {
    const enumDef: DMMF.DatamodelEnum = {
      name: 'Role',
      values: [
        { name: 'ADMIN', dbName: null },
        { name: 'USER', dbName: null },
      ],
    }

    const model = makeModel('User', [
      makeField({ name: 'id', type: 'Int', isId: true }),
      makeField({ name: 'role', type: 'Role', kind: 'enum' }),
    ])

    const result = generateRestClient(makeDmmf([model], [enumDef]))

    expect(result).toContain("export type Role =")
    expect(result).toContain("| 'ADMIN'")
    expect(result).toContain("| 'USER'")
    expect(result).toContain('role: Role')
  })

  test('handles list fields', () => {
    const model = makeModel('Post', [
      makeField({ name: 'id', type: 'Int', isId: true }),
      makeField({ name: 'tags', type: 'String', isList: true }),
    ])

    const result = generateRestClient(makeDmmf([model]))

    expect(result).toContain('tags: string[]')
  })

  test('skips relation (object) fields in interfaces', () => {
    const model = makeModel('Post', [
      makeField({ name: 'id', type: 'Int', isId: true }),
      makeField({ name: 'author', type: 'User', kind: 'object' }),
      makeField({ name: 'authorId', type: 'Int' }),
    ])

    const result = generateRestClient(makeDmmf([model]))

    expect(result).not.toMatch(/author\??\s*:\s*User/)
    expect(result).toContain('authorId: number')
  })

  test('maps all scalar types correctly', () => {
    const model = makeModel('AllTypes', [
      makeField({ name: 'id', type: 'Int', isId: true }),
      makeField({ name: 'str', type: 'String' }),
      makeField({ name: 'bool', type: 'Boolean' }),
      makeField({ name: 'int', type: 'Int' }),
      makeField({ name: 'float', type: 'Float' }),
      makeField({ name: 'bigInt', type: 'BigInt' }),
      makeField({ name: 'decimal', type: 'Decimal' }),
      makeField({ name: 'dateTime', type: 'DateTime' }),
      makeField({ name: 'json', type: 'Json' }),
      makeField({ name: 'bytes', type: 'Bytes' }),
    ])

    const result = generateRestClient(makeDmmf([model]))

    expect(result).toContain('str: string')
    expect(result).toContain('bool: boolean')
    expect(result).toContain('int: number')
    expect(result).toContain('float: number')
    expect(result).toContain('bigInt: bigint')
    expect(result).toContain('decimal: string')
    expect(result).toContain('dateTime: string')
    expect(result).toContain('json: unknown')
    expect(result).toContain('bytes: string')
  })

  test('handles uuid default as auto-generated', () => {
    const model = makeModel('User', [
      makeField({
        name: 'id',
        type: 'String',
        isId: true,
        hasDefaultValue: true,
        default: { name: 'uuid', args: [] },
      }),
      makeField({ name: 'email', type: 'String' }),
    ])

    const result = generateRestClient(makeDmmf([model]))

    expect(result).toContain('export interface UserCreateInput {')
    expect(result).toMatch(/id\?: string/)
    expect(result).toMatch(/email: string/)
  })

  test('generates empty RestApiClient for empty schema', () => {
    const result = generateRestClient(makeDmmf([]))
    expect(result).toContain('export interface RestApiClient {}')
  })
})

